int tlCameraAnimFarClipChannelChunk16::sortPriority = -1;

tlCameraAnimFarClipChannelChunk16::tlCameraAnimFarClipChannelChunk16()
{
    Init();
}

tlCameraAnimFarClipChannelChunk16::tlCameraAnimFarClipChannelChunk16(const tlCameraAnimFarClipChannelChunk16& ch)
{
    Init();
    *this = ch;
}

tlCameraAnimFarClipChannelChunk16::~tlCameraAnimFarClipChannelChunk16()
{

}

tlCameraAnimFarClipChannelChunk16::tlCameraAnimFarClipChannelChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_CAMERA_ANIM_FARCLIP_CHANNEL);
    ident = P3D_CAMERA_ANIM_FARCLIP_CHANNEL;

    tlFile* f = ch->GetFile();

    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_CAMERA_ANIM_FARCLIP_CHANNEL);
    }
}

void
tlCameraAnimFarClipChannelChunk16::Init()
{
    ident = P3D_CAMERA_ANIM_FARCLIP_CHANNEL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_CAMERA_ANIM_FARCLIP_CHANNEL);
    }
}

long 
tlCameraAnimFarClipChannelChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlCameraAnimFarClipChannelChunk16&
tlCameraAnimFarClipChannelChunk16::operator=(const tlCameraAnimFarClipChannelChunk16& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }


    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlCameraAnimFarClipChannelChunk16::operator==(const tlDataChunk& a)
{

    const tlCameraAnimFarClipChannelChunk16* aptr = dynamic_cast<const tlCameraAnimFarClipChannelChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }



    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

